return $input.all().map(item => {
  let rawText = "";
  if (item.json.text) {
    rawText = item.json.text;
  } else if (item.json.content && item.json.content.parts && item.json.content.parts[0].text) {
    rawText = item.json.content.parts[0].text;
  }

  const jsonMatch = rawText.match(/\{[\s\S]*\}/);

  let importance = 0;
  let description = "Error: JSON not found";
  let symbol = "UNKNOWN";

  if (jsonMatch) {
    try {
      const parsed = JSON.parse(jsonMatch[0]);
      importance = parsed.importance ?? 0;
      description = parsed.description ?? "No description";
      symbol = parsed.Symbol ?? "UNKNOWN"; // Pobieramy klucz!
    } catch (e) {
      description = "Parse Error: " + e.message;
    }
  }

  return {
    json: {
      Symbol: symbol,
      importance,
      description
    }
  };
});

// Pobieramy całą listę z odpowiedziami AI z poprzedniego węzła
const aiResults = $input.all();

// Pobieramy całą listę z danymi giełdowymi (upewnij się, że nazwa węzła jest poprawna!)
const stockDataList = $('Count data').all();

const now = new Date();
const formattedDate = now.toISOString().replace('T', ' ').substring(0, 16);

let finalResults = [];

// Przechodzimy przez każdy wynik od AI
for (const aiItem of aiResults) {
  const aiSymbol = aiItem.json.Symbol;

  // WYSZUKIWANIE: Szukamy w danych giełdowych obiektu z tym samym symbolem
  const matchingStock = stockDataList.find(stock => stock.json.Symbol === aiSymbol);

  // Jeśli znaleźliśmy dopasowanie, tworzymy finalny obiekt
  if (matchingStock) {
    finalResults.push({
      json: {
        "Date": formattedDate,
        "Symbol": aiSymbol,
        "Shares price": matchingStock.json["Current_Price"],
        "Level of importance [0-10]": aiItem.json.importance,
        "Trend 1D [%]": matchingStock.json["Trend_1D [%]"],
        "Trend 7D [%]": matchingStock.json["Trend_7D [%]"],
        "Trend 30D [%]": matchingStock.json["Trend_30D [%]"],
        "Trend 1Y [%]": matchingStock.json["Trend_1Y [%]"],
        "LLM description": aiItem.json.description
      }
    });
  }
}

return finalResults;

// Tworzymy prostą tabelę HTML z wynikami
let html = '<table border="1" style="border-collapse: collapse; width: 100%;">';
html += '<tr style="background-color: #f2f2f2;"><th>Symbol</th><th>Ważność</th><th>Analiza</th></tr>';

for (const item of $input.all()[0].json.data) { // 'data' to nazwa pola z węzła Aggregate
  html += `<tr>
    <td style="padding: 8px;">${item.Symbol}</td>
    <td style="padding: 8px;">${item["Level of importance [0-10]"]}</td>
    <td style="padding: 8px;">${item["LLM description"]}</td>
  </tr>`;
}
html += '</table>';

return { html_report: html };
